import React, { useEffect, useState } from "react";
import Sidebar from "../../components/Sidebar";
import { getAllProjects } from "../../api/api";

const ManageProjects = () => {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchProjects();
  }, []);

  const fetchProjects = async () => {
    try {
      const res = await getAllProjects();
      setProjects(res.data);
      setLoading(false);
    } catch (error) {
      console.log(error);
      setLoading(false);
    }
  };

  return (
    <div className="flex min-h-screen bg-gradient-to-br from-gray-100 to-gray-200">

      {/* SIDEBAR */}
      <Sidebar />

      {/* MAIN CONTENT */}
      <div className="flex-1 ml-64 px-12 py-10">

        {/* PAGE TITLE */}
        <h1 className="text-4xl font-bold text-gray-800 mb-10">
          All Projects
        </h1>

        {loading ? (
          <div className="text-center text-gray-500 text-lg">
            Loading projects...
          </div>
        ) : (
          <div className="space-y-8">

            {projects.length > 0 ? (
              projects.map((project) => (
                <div
                  key={project.id}
                  className="bg-white p-8 rounded-3xl shadow-md hover:shadow-xl transition duration-300 border border-gray-100"
                >

                  {/* HEADER */}
                  <div className="flex justify-between items-start">

                    <div>
                      <h2 className="text-2xl font-semibold text-gray-800">
                        {project.title}
                      </h2>

                      <p className="text-gray-600 mt-2">
                        {project.description}
                      </p>
                    </div>

                    {/* STATUS BADGE */}
                    <span
                      className={`px-4 py-1 rounded-full text-sm font-semibold capitalize ${
                        project.status === "completed"
                          ? "bg-gray-200 text-gray-700"
                          : project.status === "in-progress"
                          ? "bg-blue-100 text-blue-600"
                          : "bg-green-100 text-green-600"
                      }`}
                    >
                      {project.status || "open"}
                    </span>
                  </div>

                  {/* SKILLS */}
                  {project.skills && (
                    <div className="flex flex-wrap gap-3 mt-4">
                      {project.skills.map((skill, index) => (
                        <span
                          key={index}
                          className="bg-gray-100 text-gray-600 px-3 py-1 rounded-full text-sm"
                        >
                          {skill}
                        </span>
                      ))}
                    </div>
                  )}

                  {/* FOOTER */}
                  <div className="flex justify-between items-center mt-6 pt-5 border-t border-gray-200 text-sm text-gray-500">

                    {/* LEFT INFO */}
                    <div className="flex items-center gap-8">

                      <div className="flex items-center gap-2">
                        <span className="text-lg">💰</span>
                        <span className="font-medium text-gray-700">
                          ₹{project.budget}
                        </span>
                      </div>

                      <div className="flex items-center gap-2">
                        <span className="text-lg">📅</span>
                        <span>
                          {project.deadline || "Apr 20, 2026"}
                        </span>
                      </div>

                      <div className="flex items-center gap-2">
                        <span className="text-lg">🏢</span>
                        <span>
                          {project.company || "Company Name"}
                        </span>
                      </div>

                    </div>

                    {/* RIGHT SIDE */}
                    <div className="text-teal-600 font-semibold">
                      {project.proposals || 0} proposals
                    </div>

                  </div>
                </div>
              ))
            ) : (
              <div className="text-center text-gray-500 text-lg">
                No Projects Found
              </div>
            )}

          </div>
        )}
      </div>
    </div>
  );
};

export default ManageProjects;
